// ── STEP 1: Extract amount and merchant from the message ──
// Handles formats like: "450 swiggy", "swiggy 450", "spent 450 on swiggy"

const rawMessage = $input.first().json.message.text;

if (!rawMessage) {
  return [{ json: { parseSuccess: false, error: 'Empty message' } }];
}

// Find the first number in the message (that's the amount)
const amountMatch = rawMessage.match(/(\d+\.?\d*)/);

if (!amountMatch) {
  return [{ json: { parseSuccess: false, error: 'No amount found', rawMessage } }];
}

const amount = parseFloat(amountMatch[1]);

// Everything that's NOT the number is the merchant
// Remove the number, trim whitespace, remove common filler words
let merchant = rawMessage
  .replace(amountMatch[0], '')       // remove the number
  .replace(/\b(spent|paid|for|on|at|to|rs|inr|rupees)\b/gi, '')  // remove filler words
  .replace(/[^a-zA-Z0-9\s]/g, '')    // remove special characters
  .trim();

// Capitalize first letter of each word
merchant = merchant
  .split(' ')
  .filter(word => word.length > 0)
  .map(word => word.charAt(0).toUpperCase() + word.slice(1).toLowerCase())
  .join(' ');

if (!merchant) {
  merchant = 'Unknown';
}

// Generate a simple transaction ID: timestamp-based
const now = new Date();
const transactionId = 'TXN-' + now.getFullYear() +
  String(now.getMonth() + 1).padStart(2, '0') +
  String(now.getDate()).padStart(2, '0') + '-' +
  String(now.getHours()).padStart(2, '0') +
  String(now.getMinutes()).padStart(2, '0') +
  String(now.getSeconds()).padStart(2, '0');

// Month key for easy filtering later (e.g., "2026-06")
const monthKey = now.getFullYear() + '-' + String(now.getMonth() + 1).padStart(2, '0');

return [{
  json: {
    parseSuccess: true,
    transactionId,
    timestamp: now.toISOString(),
    rawMessage,
    amount,
    merchant,
    monthKey,
    source: 'telegram_text'
  }
}];

// ── STEP 2: Match merchant to a category using the keyword rules ──

// Get the parsed transaction from the 'Parse Message' node
const transaction = $('Parse Message').first().json;
const merchant = transaction.merchant.toLowerCase();

// Get all category rules from the Google Sheets read
const rules = $('Read CategoryRules').all().map(item => item.json);

// Try to find a matching keyword
let category = 'Uncategorized';
let needOrWant = 'Want';  // default

for (const rule of rules) {
  const keyword = (rule.keyword || '').toLowerCase().trim();
  if (keyword && merchant.toLowerCase().includes(keyword)) {
    category = rule.category || 'Uncategorized';
    needOrWant = rule.need_or_want || 'Want';
    break;
  }
}

return [{
  json: {
    transaction_id: transaction.transactionId,
    timestamp: transaction.timestamp,
    raw_message: transaction.rawMessage,
    amount: transaction.amount,
    merchant_vendor: transaction.merchant,
    category: category,
    subcategory: '',
    need_or_want: needOrWant,
    payment_mode: 'Unspecified',
    confidence_score: '',
    user_corrected: false,
    month_key: transaction.monthKey,
    source: transaction.source
  }
}];
